Add user association when saving a commitment:

1. Import neon at the top: import { neon } from &#x27;@neondatabase/serverless&#x27;;

2. After getting the body, before saving, check for session cookie:
const token = req.cookies.get(&#x27;kommit_session&#x27;)?.value;
let userId: number | null = null;
if (token) {
  const sql = neon(process.env.DATABASE_URL!);
  const sessions = await sql`
    SELECT u.id FROM user_sessions s
    JOIN users u ON s.user_id = u.id
    WHERE s.token = ${token} AND s.expires_at &gt; NOW()
  `;
  if (sessions.length) userId = sessions[0].id;
}

3. After saving the commitment, if userId exists, update the record:
if (userId &amp;&amp; id) {
  const sql = neon(process.env.DATABASE_URL!);
  await sql`UPDATE commitments SET user_id = ${userId} WHERE id = ${id}`;
}

